import{_ as t,c as s,e as a,o as n}from"./app-QnUuAS07.js";const l={};function o(i,e){return n(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="unity-assetbundle文件" tabindex="-1"><a class="header-anchor" href="#unity-assetbundle文件"><span>Unity AssetBundle文件</span></a></h1><h2 id="什么是assetbundle" tabindex="-1"><a class="header-anchor" href="#什么是assetbundle"><span>什么是AssetBundle</span></a></h2><p>AssetBundle 为资源的集合，可包含贴图(Textures)，材质(Materials)，声音(Audio)，动画资源(Animation Clips &amp; Animator controllers)，文字(Text assets)，甚至场景(Scenes) 等各式资源，允许游戏在运行时向远端服务器(Remote server)，要求载入AssetBundle 并且使用里头的资源。</p><p>因此可以利用AssetBundle 功能来制作关卡更新资源包，下载新的关卡资源，即是DLC (Downloadable content)。亦可用来更新游戏，例如特殊节庆时，更新游戏贴图材质，让游戏与玩家一同过节。</p><p>最常使用AssetBundle 机制莫过于是手机游戏，手机游戏发布APP 平台(eg Google Play &amp; Apple Store) 有容量限制，使用AssetBundle 机制切分游戏程序框架与游戏资源，让玩家先下载安装容量小的APP，APP启动之后，在游戏开始前再按需下载游戏资源，有效达到游戏APP 容量减量。</p><p>唯一要注意的是，AssetBundle 无法包含程序代码，即是没办法使用AssetBundle 做到程序代码更新，意味着改游戏资源时，玩家重新下载AssetBundles 即可。但若是修改游戏程序BUG时，得重新发布APP 到APP 平台，让玩家重新下载更新其游戏APP。</p><p>要如何做到更新新游戏内容而不改程序代码，如何设计程序代码成合适的组件(Components)，让关卡策划可以用既有的代码组件，新增/调整参数就能制作出新内容(eg 新关卡)。</p><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料"><span>参考资料</span></a></h2><ul><li><a href="(https://dupouyer.github.io/2020/06/24/AssetBundle%E7%A0%94%E7%A9%B6%E6%8A%A5%E5%91%8A/)">AssetBundle研究报告</a></li><li><a href="(https://www.cnblogs.com/pinkfloyd/p/6489979.html)">AssetBundle文件结构浅析</a></li><li><a href="(https://blog.codingnow.com/2014/08/unity3d_asset_bundle.html)">Unity3D asset bundle 格式简析</a></li><li><a href="(https://docs.unity3d.com/Manual/ClassIDReference.html)">Unity3D YAML Class ID Reference</a></li><li><a href="(https://dev.twsiyuan.com/2017/04/unity-assetbundles.html)">在Unity 使用AssetBundles 实作简易的游戏资源打包以及更新机制</a></li></ul>',9)])])}const u=t(l,[["render",o]]),r=JSON.parse('{"path":"/posts/unity_asset_bundle_file_format.html","title":"Unity AssetBundle文件","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["游戏开发"],"tag":["Unity"],"sticky":10},"headers":[{"level":2,"title":"什么是AssetBundle","slug":"什么是assetbundle","link":"#什么是assetbundle","children":[]},{"level":2,"title":"参考资料","slug":"参考资料","link":"#参考资料","children":[]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"tx7do","username":"tx7do","email":"yanglinbo@gmail.com","commits":1,"url":"https://github.com/tx7do"},{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":1,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"9ef37f328daa237305bc6e7951463194c909dc4a","time":1706334465000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add post."}]},"filePathRelative":"posts/unity_asset_bundle_file_format.md","excerpt":"\\n<h2>什么是AssetBundle</h2>\\n<p>AssetBundle 为资源的集合，可包含贴图(Textures)，材质(Materials)，声音(Audio)，动画资源(Animation Clips &amp; Animator controllers)，文字(Text assets)，甚至场景(Scenes) 等各式资源，允许游戏在运行时向远端服务器(Remote server)，要求载入AssetBundle 并且使用里头的资源。</p>\\n<p>因此可以利用AssetBundle 功能来制作关卡更新资源包，下载新的关卡资源，即是DLC (Downloadable content)。亦可用来更新游戏，例如特殊节庆时，更新游戏贴图材质，让游戏与玩家一同过节。</p>"}');export{u as comp,r as data};
